// Validar datos de entrada
const data = $input.first().json.body;

if (!data.user_id || !data.image_base64) {
  throw new Error('Faltan campos requeridos: user_id, image_base64');
}

return [{
  json: {
    user_id: data.user_id,
    image_base64: data.image_base64,
    timestamp: new Date().toISOString()
  }
}];

// Preparar imagen para OpenAI Vision
const imageData = $input.first().json;

// Si la imagen viene como base64, preparar el formato
let imageUrl = imageData.image_base64;
if (!imageUrl.startsWith('data:')) {
  imageUrl = `data:image/jpeg;base64,${imageUrl}`;
}

return [{
  json: {
    user_id: imageData.user_id,
    image_data: imageUrl,
    timestamp: imageData.timestamp
  }
}];

