// Parsear respuesta de OpenAI
const response = $input.first().json;
const content = response.choices[0].message.content;

let extractedData;
try {
  // Limpiar respuesta por si tiene markdown
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  extractedData = JSON.parse(jsonMatch ? jsonMatch[0] : content);
} catch (e) {
  extractedData = {
    monto: null,
    fecha_factura: null,
    proveedor: 'No detectado',
    concepto: content.substring(0, 100),
    tipo_gasto: 'otros'
  };
}

return [{
  json: {
    user_id: $input.first().json.user_id,
    monto: extractedData.monto || 0,
    fecha_factura: extractedData.fecha_factura || new Date().toISOString().split('T')[0],
    proveedor: extractedData.proveedor || 'No detectado',
    concepto_ocr: extractedData.concepto || content,
    tipo_gasto: extractedData.tipo_gasto || 'otros',
    image_data: $input.first().json.image_data
  }
}];

// Preparar respuesta para el frontend
const data = $input.first().json;

return [{
  json: {
    success: true,
    extracted_data: {
      monto: data.monto,
      fecha_factura: data.fecha_factura,
      proveedor: data.proveedor,
      tipo_gasto: data.tipo_gasto,
      concepto: data.concepto_ocr
    },
    message: 'Factura procesada exitosamente con OpenAI Vision'
  }
}];
